class Solution:
    def kItemsWithMaximumSum(self, numOnes, numZeros, numNegOnes, k):
        best = None
        for a in range(min(numOnes, k) + 1):
            for b in range(min(numZeros, k - a) + 1):
                c = k - a - b
                if 0 <= c <= numNegOnes:
                    val = a - c
                    if best is None or val > best:
                        best = val
        return best

