var kItemsWithMaximumSum = function(numOnes, numZeros, numNegOnes, k) {
    const ones = Math.min(numOnes, k);
    k -= ones;
    const zeros = Math.min(numZeros, k);
    k -= zeros;
    const negs = Math.min(numNegOnes, k);
    return ones - negs;
};
